from itertools import count, islice, product
def agen():
    yield from range(10)
    for digs in count(3, step=2):
        for first in "123456789":
            for left in product("012345678", repeat=(digs-3)//2):
                left = "".join(left)
                mx = int(max(first+left))
                for mid in "".join(map(str, range(mx+1, 10))):
                    yield int(first + left + mid + left[::-1] + first)
print(list(islice(agen(), 57))) # _Michael S. Branicky_, Feb 28 2026

